form:Form.form:Scripts:
		var MyDDO;       
var MyOBJ;
var MyTURList;   
var MyTURSelect;
var MyESTList;
var MyESTSelect;

function ObtenerTurnos()
{	
var proxy;
var TURNOS;
var retval;
var t;

proxy=new NomadProxy();
TURNOS=proxy.SQLService().GetOBJ(Ctrl("main").getResource("TIPOS_DE_HORAS"),"<DATOS />");

retval=new Array();
if (Ctrl("main").GetMode()=="EDIT" || Ctrl("main").GetMode()=="DEBUG")
{
	retval[""]=new Object();
	retval[""].id   ="";
	retval[""].label="Eliminar";
	retval[""].color="";
}

for (t=0; t<TURNOS.Child.length; t++)
	retval[TURNOS.Child[t].id.toString()]=TURNOS.Child[t];


return retval;
}             

function ObtenerEstructuras(ids)
{	
var proxy;
var ESTRUCTURAS;
var retval;
var t,newids,key,sep;

newids=new Array();	      
ids=ids.split("|");
for (t=0; t<ids.length; t++)
	if (ids[t])
		newids[ids[t]]=1;

ids=""; sep="";		
for (key in newids)
{
	ids+=sep+key;
	sep=",";
}

retval=new Array();
if (ids!="")
{
	proxy=new NomadProxy();
	ESTRUCTURAS=proxy.SQLService().GetOBJ(Ctrl("main").getResource("ESTRUCTURAS"),"<DATOS ids=\""+ids+"\"/>");

	for (t=0; t<ESTRUCTURAS.Child.length; t++)
		retval[ESTRUCTURAS.Child[t].id.toString()]=ESTRUCTURAS.Child[t];
}

return retval;
}             

function SetTurno(myId)
{ 
if (Ctrl("main").GetMode()!="EDIT" && Ctrl("main").GetMode()!="DEBUG") return;

MyTURSelect=myId;
DrawReference(MyTURList, "CONT_TUR_REFER", MyTURSelect, "SetTurno");

if (MyTURSelect=="")
	MyOBJ.SelectStyle("000000","BAR");
else
	MyOBJ.SelectStyle(MyTURList[MyTURSelect].color,"TIME");
}

function SetEstruct(myId)
{ 
if (Ctrl("main").GetMode()!="EDIT" && Ctrl("main").GetMode()!="DEBUG") return;

MyESTSelect=myId;
DrawReference(MyESTList, "CONT_EST_REFER", MyESTSelect, "SetEstruct");

if (MyESTSelect=="")
	MyOBJ.SelectStyle("000000","BAR");
else
	MyOBJ.SelectStyle(MyESTList[MyESTSelect].color,"TIME");
}

function DrawReference(arr, ContainerName, KeySelect, funcName)
{                         
var HTMLoutput="", key;
var TrgObj=document.getElementById(ContainerName);

HTMLoutput+="<TABLE style='width:100%;height:100%cursor:default;font-family:arial;font-size:10px;font-weight:bold;color:#000000;background-color:#F0F0D0;' >";
for (key in arr)
{
	if (arr[key].color=="")
		HTMLoutput+="<TR style='height:20px;"+(key==KeySelect?"background-color:#F0F0A0;":"")+"' >"
		           +"<TD onclick='"+funcName+"(\""+key+"\");' style='border-bottom:1px dotted #808080;' ><img src='../Images/Buttons/cancel_n.gif' /></TD>"
		           +"<TD onclick='"+funcName+"(\""+key+"\");' style='border-bottom:1px dotted #808080;' >"+arr[key].label+"</TD>"
		           +"</TR>";
	else
		HTMLoutput+="<TR style='height:20px;"+(key==KeySelect?"background-color:#F0F0A0;":"")+"' >"
		           +"<TD onclick='"+funcName+"(\""+key+"\");' style='border-bottom:1px dotted #808080;width:30px;font-size:1px;' ><div style='padding:0px;height:12px;background-color:#"+arr[key].color+";' ></div></TD>"
		           +"<TD onclick='"+funcName+"(\""+key+"\");' style='border-bottom:1px dotted #808080;' >"+arr[key].label+"</TD>"
		           +"</TR>";
}
HTMLoutput+="</TABLE>";

TrgObj.style.height=TrgObj.offsetHeight;
TrgObj.innerHTML=HTMLoutput;
}      

function ColorAssign(arr)
{
var t, MyCols="DD0000|00DD00|0000DD|00DDDD|DD00DD|DDDD00|0099DD|9900DD|99DD00|00DD99|DD0099|DD9900".split("|");

t=0;
for (key in arr)
{
	arr[key].color=MyCols[t];
	t++;
}
}


function Initialize()
{
	var strini, t, c; 
	if (Ctrl("main").GetMode()=="DEBUG") 
		MyDDO=new nomadDOM(Ctrl("main").getResource("DEBUG"));
	else
		MyDDO=new nomadDOM(DOM2String(Ctrl("main").GetLastDoc("RS")));

	//Inicio las Variables
	strini="";
	for (t=0; t<MyDDO.e_dias; t++)    
	{
		if (t!=0) strini+="|";  
		c="";
		for (d=0; d<MyDDO.HORA_TUR_DET.Child.length; d++)
		{               
			if (MyDDO.HORA_TUR_DET.Child[d].e_posicion==t.toString())                    
					c=MyDDO.HORA_TUR_DET.Child[d].oi_turno.value.toString();  			
		}                                                            
		strini+=c;
	}
	Ctrl("TUR").SetXValue(strini);

	strini="";
	for (t=0; t<MyDDO.e_dias; t++)    
	{
		if (t!=0) strini+="|";         
		c="";
		for (d=0; d<MyDDO.HORA_TUR_DET.Child.length; d++)
		{               
			if (MyDDO.HORA_TUR_DET.Child[d].e_posicion==t.toString())
				c=MyDDO.HORA_TUR_DET.Child[d].oi_estructura.value.toString();
		} 
		strini+=c;       
	}
	Ctrl("EST").SetXValue(strini);		


	strini="";
	if (MyDDO.d_tipohorario=="R")
		for (t=0; t<MyDDO.ESCUADRAS.Child.length; t++)
			strini+=(t==0?"":"|")+MyDDO.ESCUADRAS.Child[t].e_avance;
	Ctrl("ESQ").SetXValue(strini);		


	//Horarios	
	MyTURSelect="";   
	MyTURList=ObtenerTurnos();	   
	DrawReference(MyTURList, "CONT_TUR_REFER", MyTURSelect,"SetTurno");

	//Estructuras
	MyESTSelect="";              
	MyESTList=ObtenerEstructuras(Ctrl("EST").GetXValue());
	ColorAssign(MyESTList);
	DrawReference(MyESTList, "CONT_EST_REFER", MyESTSelect,"SetEstruct");

	//Creo el Objeto de Edicion
	MyOBJ=HTMLTimeBarSelected("CONT_HORARIO","",AddData,null);
	MyOBJ.SetAxisMode("SERIE/DATE");
	MyOBJ.SetAxisDate("20000101","20000102", 1, 1, 12);
	MyOBJ.ShowMonth=false;
	MyOBJ.OnSelect=OnSelectData;

	MyOBJ.AddSerie("TUR","Turnos","Definicion del Horario");
	MyOBJ.AddSerie("EST","Terminal" ,"Terminal donde debe Marcar");

	//Series Adicionales
	if (MyDDO.d_tipohorario=="R")
		for (t=0; t<MyDDO.ESCUADRAS.Child.length; t++)
			MyOBJ.AddSerie("ESC "+MyDDO.ESCUADRAS.Child[t].c_escuadra, MyDDO.ESCUADRAS.Child[t].d_escuadra, "Previsualizacion de la Escuadra "+MyDDO.ESCUADRAS.Child[t].d_escuadra);

	//Dibujo la Series		
	MyOBJ.Draw(); 

	//Modo Edicion
	if (Ctrl("main").GetMode()=="EDIT" || Ctrl("main").GetMode()=="DEBUG") 
	{
		MyOBJ.EditStart();           
		MyOBJ.SelectStyle("000000","BAR");
	}

	//otros               
	var Now=new Date();

	Ctrl("MONTH_POS").SetXValue((Now.getFullYear()*100+(Now.getMonth()+1)).toString());
	MONTH_CHANGE(Ctrl("MONTH_POS"));
}

function MONTH_PREV()
{
var objMONTH=Ctrl("MONTH_POS");
var NewDate=new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10)-2, 1);
objMONTH.SetXValue((NewDate.getFullYear()*100+(NewDate.getMonth()+1)).toString());
MONTH_CHANGE(objMONTH);
}

function MONTH_NEXT()
{             
var objMONTH=Ctrl("MONTH_POS");
var NewDate=new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10), 1);
objMONTH.SetXValue((NewDate.getFullYear()*100+(NewDate.getMonth()+1)).toString());
MONTH_CHANGE(objMONTH);
}

function AddData(obj, seccion, he, hs)
{        
var t, MyData;

//Agregar Turno             
switch(seccion)
{
	case "TUR": 
		MyData=Ctrl("TUR").GetXValue().split("|");

	 	for (t=he; t<hs; t++)
	 		MyData[t % MyData.length]=MyTURSelect;  

	 	Ctrl("TUR").SetXValue(MyData.join("|"));
	 	DrawTurno();
	break;

	case "EST":
		MyData=Ctrl("EST").GetXValue().split("|");

	 	for (t=he; t<hs; t++)
	 		MyData[t % MyData.length]=MyESTSelect;  

	 	Ctrl("EST").SetXValue(MyData.join("|"));
	 	DrawEstructura();
	break;   

	default:                                                                                     
		MyData=Ctrl("ESQ").GetXValue().split("|");   
		len   =Ctrl("TUR").GetXValue().split("|").length;

		for (d=0; d<MyDDO.ESCUADRAS.Child.length; d++)
		{
			id="ESC "+MyDDO.ESCUADRAS.Child[d].c_escuadra;

		 	if (id==seccion)
		 	{          
		 		val=(parseInt(MyData[d],10)-MyOBJ.SelectEndTime+MyOBJ.SelectStartTime) % len;
		 		if (val<0) val+=len;
				MyData[d]=val.toString();
			}
		}

	 	Ctrl("ESQ").SetXValue(MyData.join("|"));
	 	DrawTurno();
	break;
}
}

function MONTH_CHANGE(objMONTH)
{                             
var objMONTH=Ctrl("MONTH_POS");

var lastDate=new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10), 1);
MyOBJ.SetAxisDate(objMONTH.GetXValue()+"01",date2str(lastDate), 1, 1, 12);
MyOBJ.Draw();               

//Dibujo	          
DrawTurno();
DrawEstructura();
}            

function DrawTurno()
{
var t,d,horpre,horact,MyData,horantval;

//Limpio los Valores	
MyOBJ.ClearValue("TUR");
MyData=Ctrl("TUR").GetXValue().split("|");

horpre="";
horact="";                                   
horantval=0;

//Actualizo los Turnos	
for (t=MyOBJ.StartTime; t<=MyOBJ.EndTime; t++)
{      
	horact=MyData[t % MyData.length];

	if ((horact!=horpre) || (t==MyOBJ.EndTime))
	{                                                

		if (horpre!="")
			MyOBJ.SetValue(
				"TUR",
				horantval,
				t,
				MyTURList[horpre].label,
				MyTURList[horpre].color,
				MyTURList[horpre].color,
				"Turno: "+MyTURList[horpre].label+" desde "+int2date(horantval)+" a "+int2date(t)	
			);

		horantval=t; horpre=horact;
	}
}
MyOBJ.ReDraw("TUR");

//Actualizo los Rotativos	
if (MyDDO.d_tipohorario=="R")
{                          
	MyESQ=Ctrl("ESQ").GetXValue().split("|");
	for (d=0; d<MyDDO.ESCUADRAS.Child.length; d++)
	{
		id="ESC "+MyDDO.ESCUADRAS.Child[d].c_escuadra;
		av=parseInt(MyESQ[d],10);

		horpre="";
		horact="";                                   
		horantval=0;

		//Actualizo los Turnos	
		MyOBJ.ClearValue(id);
		for (t=MyOBJ.StartTime; t<=MyOBJ.EndTime; t++)
		{      
			horact=MyData[(t+av) % MyData.length];

			if ((horact!=horpre) || (t==MyOBJ.EndTime))
			{                                                

				if (horpre!="")
					MyOBJ.SetValue(
						id,
						horantval,
						t,
						MyTURList[horpre].label,
						MyTURList[horpre].color,
						MyTURList[horpre].color,
						"Turno: "+MyTURList[horpre].label+" desde "+int2date(horantval)+" a "+int2date(t)	
					);

				horantval=t; horpre=horact;
			}
		}

		MyOBJ.ReDraw(id);
	}
}

}

function DrawEstructura()
{
var t,d,horpre,horact,MyData,horantval;

//Limpio los Valores	
MyOBJ.ClearValue("EST");
MyData=Ctrl("EST").GetXValue().split("|");

horpre="";
horact="";                                   
horantval=0;

//Actualizo los Turnos	
for (t=MyOBJ.StartTime; t<=MyOBJ.EndTime; t++)
{      
	horact=MyData[t % MyData.length];

	if ((horact!=horpre) || (t==MyOBJ.EndTime))
	{                                                

		if (horpre!="")
			MyOBJ.SetValue(
				"EST",
				horantval,
				t,
				MyESTList[horpre].label,
				MyESTList[horpre].color,
				MyESTList[horpre].color,
				"Terminal: "+MyESTList[horpre].label+" desde "+int2date(horantval)+" a "+int2date(t)	
			);

		horantval=t; horpre=horact;
	}
}
MyOBJ.ReDraw("EST");
}

function CleanEstruct()
{                                          
var newESTList=new Array();

 	MyESTSelect="";
MyData=Ctrl("EST").GetXValue().split("|");
for (t=MyOBJ.StartTime; t<=MyOBJ.EndTime; t++)
{      
	horact=MyData[t % MyData.length];
	if (horact)
	{
		if (MyESTSelect=="") MyESTSelect=horact;
		newESTList[horact]=MyESTList[horact];
	}
}

MyESTList=newESTList;

ColorAssign(MyESTList);
DrawReference(MyESTList, "CONT_EST_REFER", MyESTSelect,"SetEstruct");

DrawEstructura();
}

function AddEstruct()
{
openNewFlowWait(
	"NucleusRH.Base.Tiempos_Trabajados.Terminales.TERMINAL.combo.flow",
	"HELP",
	"<helper-mess/>",
	new ObjEstr(),
	"M"
);
}

function ObjEstr()
{                 
this.processResult=function(xmlstring)
{                           
	MyXML=new nomadDOM(xmlstring);

	if (MyXML.id)
	{		                          
		MyESTList[MyXML.id]=new Object();
		MyESTList[MyXML.id].id   =MyXML.id;
		MyESTList[MyXML.id].label=MyXML.text;
		MyESTList[MyXML.id].color="000000";

		ColorAssign(MyESTList);
		DrawReference(MyESTList, "CONT_EST_REFER", MyESTSelect,"SetEstruct");
	}
}
}

function OnSelectData(obj, seccion)
{                       
 	switch(seccion)
 	{
 		case "TUR":                        
 			if (MyTURSelect=="") MyOBJ.SelectStyle("000000","BAR");
 			              else MyOBJ.SelectStyle(MyTURList[MyTURSelect].color,"TIME");
 		break;

 		case "EST":
 			if (MyESTSelect=="") MyOBJ.SelectStyle("000000","BAR");
 			                else MyOBJ.SelectStyle(MyESTList[MyESTSelect].color,"TIME");
 		break;

 		default:
 			MyOBJ.SelectStyle("000000","ARROW");
 		break;

 	}
}

function CheckDef(MyObj)
{
//Verificacion de Turnos
MyData=Ctrl("TUR").GetXValue().split("|");
for (t=0; t<MyData.length; t++)
	if (MyData[t]=="")
	{
      MyObj.SetError("Existen Dias sin Definicion de Horario");
		return false;			
	}

//Verificacion de Estructura
MyData=Ctrl("EST").GetXValue().split("|");
for (t=0; t<MyData.length; t++)
	if (MyData[t]=="")
	{
      MyObj.SetError("Existen Dias sin Definicion de Estructura");
		return false;			
	}

//Comprobacion de compatibilidad de Turnos
MyData=Ctrl("TUR").GetXValue().split("|");
for (t=0; t<MyData.length; t++)
{                   
  d=(t==0?MyData.length-1:t-1);

 	if (MyTURList[MyData[d]].ed?false:true) continue;
 	if (MyTURList[MyData[t]].st?false:true) continue;
 	if (
	 		parseInt(MyTURList[MyData[d]].ed,10) > parseInt(MyTURList[MyData[t]].st,10)+1440
 		)
 	{
      MyObj.SetError("El turno '"+MyTURList[MyData[d]].label+"' no puede estar antes del turno '"+MyTURList[MyData[t]].label+"'.");
		return false;			
 	}

}


return true;
}

function ABMTurnos()
{
openNewFlowWait(
	"NucleusRH.Base.Tiempos_Trabajados.Turnos.flow",
	"initialize",
	"",
	new ObjTurno(),
	"L"
);
}

function ShowTurno()
{
if (MyTURSelect=="") return;
openNewFlowWait(
	"NucleusRH.Base.Tiempos_Trabajados.Turnos.flow",
	"SHOW",
	"<ROWS><ROW id=\""+MyTURSelect+"\" /></ROWS>",
	new ObjTurno(),
	"L"
);
}

function ObjTurno()
{                 
this.processResult=function(xmlstring)
{
	//Horarios	
	MyTURSelect="";   
	MyTURList=ObtenerTurnos();	   
	DrawReference(MyTURList, "CONT_TUR_REFER", MyTURSelect,"SetTurno");
}
}
